import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    ptr = 0
    N = int(input_data[ptr]); ptr += 1
    M = int(input_data[ptr]); ptr += 1
    K = int(input_data[ptr]); ptr += 1

    MOD = 998244353

    board = []
    for i in range(N):
        row = []
        for j in range(N):
            row.append(int(input_data[ptr]))
            ptr += 1
        board.append(row)

    stamps = []
    for m in range(M):
        stamp = []
        for i in range(3):
            s_row = []
            for j in range(3):
                s_row.append(int(input_data[ptr]))
                ptr += 1
            stamp.append(s_row)
        stamps.append(stamp)

    placements = []

    for _ in range(K):
        best_gain = -1
        best_move = None

        for m in range(M):
            for r in range(N - 2):
                for c in range(N - 2):
                    current_gain = 0
                    for dr in range(3):
                        for dc in range(3):
                            old_val = board[r + dr][c + dc]
                            new_val = (old_val + stamps[m][dr][dc]) % MOD
                            current_gain += (new_val - old_val)

                    if current_gain > best_gain:
                        best_gain = current_gain
                        best_move = (m, r, c)

        if best_move and best_gain > 0:
            m, r, c = best_move
            placements.append((m, r, c))
            for dr in range(3):
                for dc in range(3):
                    board[r + dr][c + dc] = (board[r + dr][c + dc] + stamps[m][dr][dc]) % MOD
        else:
            break

    for m, r, c in placements:
        print(f"{m} {r} {c}")

solve()

